import { Component, Element, Event, EventEmitter, h, Host, Listen, Prop, State, Watch } from '@stencil/core';
import { CalendarMode, CalendarSize } from '../wdpr-calendar.model';
import { startOfMonth, endOfMonth, getNextMonth, getPreviousMonth, isAfterDay, isBeforeDay } from '../../../utils/date.utils';
import { twMerge } from '../../../utils/utils';
import { isMobile } from '../../../utils/breakpoint.utils';

@Component({
  tag: 'wdpr-double-calendar',
  shadow: true,
  styles: ':host(.full-width) { width: 100%; }',
})
export class WdprDoubleCalendar {
  @Element() el: HTMLWdprDoubleCalendarElement;

  @State() private _isMobileView: boolean = false;
  @State() private _isPrevMonthDisabled: boolean = false;
  @State() private _isNextMonthDisabled: boolean = false;

  /**
   * Selected date.
   * Only used when `mode="single"`.
   * @type {Date | null}
   * @default null
   */
  @Prop() selectedDate: Date | null = null;

  /**
   * The start date of the selected range.
   * Only used when `mode="range"`.
   *
   * @type {Date | null}
   * @default null
   */
  @Prop() startDate: Date | null = null;

  /**
   * The end date of the selected range.
   * Only used when `mode="range"`.
   *
   * @type {Date | null}
   * @default null
   */
  @Prop() endDate: Date | null = null;

  /**
   * Currently hovered date in the calendar.
   * @type {Date | null}
   * @default null
   */
  @Prop() hoverDate: Date | null = null;

  /**
   * The calendar mode.
   * - `single`: user selects one date
   * - `range`: user selects a start and end date
   *
   * @default "single"
   * @type {"single" | "range"}
   */
  @Prop() mode: CalendarMode = 'single';

  /**
   * Whether to always render six weeks in the calendar view.
   * Useful for keeping calendar height consistent.
   *
   * @default false
   * @type {boolean}
   */
  @Prop() enableSixWeeks: boolean = false;

  /**
   * The date format string (uses date-fns format syntax).
   *
   * @default "MM/dd/yyyy"
   * @example "dd-MM-yyyy"
   * @type {string}
   */
  @Prop() format: string = 'MM/dd/yyyy';

  /**
   * The extra info for the date cells
   * @type { Map<string, HTMLElement>}
   */
  @Prop() extras: Map<string, HTMLElement> = new Map();

  /**
   * Flag that shows or hide the calendar borders
   * @default true
   * @type {boolean}
   */
  @Prop() displayBorder: boolean = true;

  /**
   * Optional predicate to indicate a day is blocked (disabled).
   * Provided by the parent calendar.
   */
  @Prop() isDateBlocked?: (date: Date) => boolean;

  /**
   * Whether this disabled cells should set a slash in the disabled dates or not.
   * @default false
   */
  @Prop({ reflect: true }) showDisabledSlash: boolean = false;

  /**
   * The calendar size.
   *
   * @default "medium"
   * @type {"small" | "medium"}
   */
  @Prop({ reflect: true }) size: CalendarSize = 'medium';

  /**
   * The date currently setting as the Maximum end date in Range mode.
   * Internal use only.
   * @type {Date | null}
   */
  @Prop() maxRangeDate: Date | null = null;

  /**
   * The date that will be used to display the month in the calendar.
   * Default is the current date.
   * @type {Date}
   */
  @Prop() displayDate: Date = new Date();

  /**
   * The minimum date formatted.
   * @type {Date | null}
   */
  @Prop() minDate: Date | null = null;

  /**
   * The maximum date formatted.
   * @type {Date | null}
   */
  @Prop() maxDate: Date | null = null;

  /**
   * Currently focused date in the calendar.
   * @type {Date | null}
   * @default null
   */
  @Prop() focusDate: Date | null = null;

  @Prop() isReadOnly: boolean = false;

  @Prop() fullWidth?: boolean = false;

  @Prop() isDateDot?: (date: Date) => boolean;
  @Prop() getDatePrice?: (date: Date | string) => number | undefined;

  /**
   * Fired when the previous month button is clicked.
   * @event
   * @type {void}
   */
  @Event({ eventName: 'previousMonth' }) previousMonth: EventEmitter<void>;

  /**
   * Fired when the next month button is clicked.
   * @event
   * @type {void}
   */
  @Event({ eventName: 'nextMonth' }) nextMonth: EventEmitter<void>;

  /**
   * Fired when a date is selected.
   * Emits an object with the selected date.
   *
   * @event
   * @type {{ date: string }} Object with ISO date string (e.g. { date: "06/19/2025" })
   */
  @Event({ eventName: 'dateSelected' }) dateSelected: EventEmitter<{ date: string }>;

  /**
   * Fired when a date is hovered.
   * @event
   * @type {{ date: string }}  Object with ISO date string (e.g. { date: "06/19/2025" })
   */
  @Event({ eventName: 'dateHover' }) dateHover: EventEmitter<{ date: string }>;

  /**
   * Fired when new date is being focused.
   * @event
   * @type {{ date: string }}  Object with ISO date string (e.g. { date: "06/19/2025" })
   */
  @Event() focusMoveOut: EventEmitter<{ date: string }>;

  @Watch('displayDate')
  @Watch('minDate')
  @Watch('maxDate')
  validateButtons() {
    const prevMonth = getPreviousMonth(this.displayDate);
    const nextMonth = getNextMonth(this.displayDate);

    const lastDayOfPrevMonth = endOfMonth(prevMonth);
    const firstDayOfNextMonth = nextMonth;

    this._isPrevMonthDisabled = this.minDate && isBeforeDay(lastDayOfPrevMonth, this.minDate);
    this._isNextMonthDisabled = this.maxDate && isAfterDay(firstDayOfNextMonth, this.maxDate);
  }

  @Watch('focusDate')
  @Watch('isMobileView')
  handleFocusDateChanged() {
    this._checkAndCorrectMonthView();
  }

  @Listen('resize', { target: 'window' })
  handleResize() {
    this._isMobileView = isMobile();
  }

  componentWillLoad() {
    this.validateButtons();
    this.handleResize();
  }

  private _checkAndCorrectMonthView() {
    if (!this.focusDate) return;

    const firstMonthEnd = endOfMonth(this.displayDate);
    const firstMonthStart = startOfMonth(this.displayDate);

    const nextMonth = getNextMonth(this.displayDate);
    const secondMonthEnd = endOfMonth(nextMonth);

    if (this.focusDate < firstMonthStart) {
      this.previousMonth.emit();

      return;
    }

    if (this.focusDate > secondMonthEnd) {
      this.nextMonth.emit();

      return;
    }

    if (this._isMobileView) {
      if (this.focusDate > firstMonthEnd) {
        this.nextMonth.emit();
      }
    }
  }

  private _onPreviousMonth = () => {
    this.previousMonth.emit();
  };

  private _onNextMonth = () => {
    this.nextMonth.emit();
  };

  private _onDateSelected = (event: CustomEvent<{ date: string }>) => {
    event.stopPropagation();
    this.dateSelected.emit(event.detail);
  };

  private _onDateHover = (event: CustomEvent<{ date: string }>) => {
    event.stopPropagation();
    this.dateHover.emit(event.detail);
  };

  private _onFocusMoveOut = (event: CustomEvent<{ date: string }>) => {
    event.stopPropagation();
    this.focusMoveOut.emit(event.detail);
  };

  private get _calendarWrapperClasses() {
    const margin = this.size === 'xsmall' ? 'gap-300' : 'gap-400';

    return twMerge('md:flex', margin);
  }

  private get _containerClasses() {
    const width = this.fullWidth ? 'w-full' : '';

    return twMerge('flex gap-200 items-start', width);
  }

  private get _commonCalendarProps() {
    return {
      mode: this.mode,
      enableSixWeeks: this.enableSixWeeks,
      startDate: this.startDate,
      endDate: this.endDate,
      hoverDate: this.hoverDate,
      focusDate: this.focusDate,
      selectedDate: this.selectedDate,
      format: this.format,
      minDate: this.minDate,
      maxDate: this.maxDate,
      extras: this.extras,
      displayBorder: this.displayBorder,
      maxRangeDate: this.maxRangeDate,
      showDisabledSlash: this.showDisabledSlash,
      size: this.size,
      fullWidth: this.fullWidth,
      isReadOnly: this.isReadOnly,
      onDateSelected: this._onDateSelected,
      onDateHover: this._onDateHover,
      onFocusMoveOut: this._onFocusMoveOut,
      isDateBlocked: this.isDateBlocked,
      isDateDot: this.isDateDot,
      getDatePrice: this.getDatePrice,
    };
  }

  render() {
    const nextMonth = getNextMonth(this.displayDate);

    return (
      <Host class={{ 'full-width': this.fullWidth }}>
        <section class={this._calendarWrapperClasses} part="double-calendar">
          <span class="hidden md:block pt-[165px]">
            <wdpr-icon-button variant="primary" iconName="previous" onClicked={this._onPreviousMonth} a11yLabel="Previous Month" disabled={this._isPrevMonthDisabled} />
          </span>

          <div class={this._containerClasses}>
            <wdpr-single-calendar
              {...this._commonCalendarProps}
              displayDate={this.displayDate}
              monthHeaderVariant={`${this._isMobileView ? 'with-arrows' : 'default'}`}
              exportparts="calendar-surface"
            />

            <wdpr-single-calendar class="hidden md:block" monthHeaderVariant="default" displayDate={nextMonth} {...this._commonCalendarProps} exportparts="calendar-surface" />
          </div>

          <span class="hidden md:block pt-[165px]">
            <wdpr-icon-button variant="primary" iconName="next" onClicked={this._onNextMonth} a11yLabel="Next Month" disabled={this._isNextMonthDisabled} />
          </span>
        </section>
      </Host>
    );
  }
}
